import React from 'react';
import { Icon as CarbonIcon } from '@carbon/react';

const Icon = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonIcon
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonIcon>
    );
};

Icon.defaultProps = {
    className: ''
};

export default Icon;
